  ('promotion-6f0ba476-moex-00145', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '下列信託行為課稅規定，何者敘述錯誤？', '["信託財產發生之收入，受託人應於所得發生年度，按所得類別依本法規定，減除成本、必要費 用及損耗後，分別計算受益人之各類所得額，由受益人併入當年度所得額", "信託成立時，委託人為營利事業之信託契約，信託利益之全部或一部之受益人為非委託人者， 該受益人應將享有信託利益之權利價值，併入成立年度之所得額，依規定課徵所得稅", "信託財產因信託行為成立，委託人與受託人間移轉或為其他處分者，不適用視為銷售，免徵營 業稅", "土地為信託財產者，因信託行為成立，委託人與受託人間移轉所有權，應課徵土地增值稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00146', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依現行稅法規定，下列不動產交易所得之課稅規定，何者正確？', '["個人出售民國104年以前取得之土地，其交易所得歸屬綜合所得稅之財產交易所得", "營利事業出售民國105年以後取得之土地，併入營利事業所得額，合併計稅", "個人出售民國105年以後取得之房屋，其交易所得分離課稅，稅率20%", "營利事業出售民國104年以前取得之房屋，併入營利事業所得額，合併計稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00147', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依現行貨物稅條例所規定的應稅貨物，不包括下列何者？', '["販賣機中販賣的瓶裝碳酸飲料", "設廠機製之稀釋天然果蔬汁", "沿街販售的手搖飲", "便利商店販賣的罐裝運動飲料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00148', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依所得稅法規定，個人與證券商或銀行從事結構型商品交易所得，下列敘述何者正確？', '["歸屬於其他所得，採20%分離課稅", "歸屬於財產交易所得，採10%分離課稅", "歸屬於其他所得，採10%分離課稅", "歸屬於財產交易所得，採合併計稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00149', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '個人111年所得基本稅額條例之敘述，下列何者錯誤？', '["一般所得稅額高於或等於基本稅額者，依一般所得稅額繳納所得稅", "個人一般所得稅額之計算包括按結算申報所計算之應納綜合所得稅額，應加計採分開計稅之股 利及盈餘總額計算之稅額，減除依其他法律規定之各項投資抵減稅額", "個人基本稅額之計算＝（基本所得額－670萬元）×20%", "個人海外所得包括非中華民國來源所得、大陸地區來源所得、港澳地區來源所得，當地法律規 定繳納的所得稅，得扣抵基本稅額，扣抵金額不得超過因加計海外所得，而依規定計算增加的 基本稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00150', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '甲公司為加值型兼營營業人，當期112年5～6月銷貨之應稅銷售額為5,000,000元，外銷內銷各 半，另免稅銷售額為1,300,000元。當期進貨及費用之進項稅額為172,500元，其中屬於交際應酬 之進項稅額有 10,000 元；另有取得固定資產之進項稅額有 25,000 元。試問甲公司當期不得扣抵 比例為若干？又可退還之稅額為新臺幣若干元？設上期累積留抵稅額有5,000元。', '["21%，可退還稅額為28,125元", "21%，可退還稅額為23,125元", "20%，可退還稅額為25,000元", "20%，可退還稅額為30,000元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00151', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依加值型及非加值型營業稅法，銷售下列貨物課徵營業稅規定，何者正確？', '["金條、金幣進口及在境內銷售均免徵營業稅", "櫻桃進口及在境內銷售均免徵營業稅", "進口肥料及飼料免徵營業稅，在境內銷售肥料及飼料需課徵營業稅", "進口國際運輸用之船舶、航空器及遠洋漁船免徵營業稅，其提供之勞務亦免徵營業稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00152', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依契稅條例規定，委託人以不動產為信託財產，受託人依信託本旨移轉信託財產與委託人以外之 歸屬權利人時，契稅納稅義務人為何？又其契稅稅率為何？', '["納稅義務人為委託人，稅率為4%", "納稅義務人為受託人，稅率為6%", "納稅義務人為歸屬權利人，稅率為6%", "納稅義務人為受託人，稅率為4%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00153', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依土地稅法規定，下列敘述何者錯誤？', '["已規定地價之土地，設定典權時，出典人應依本法規定預繳土地增值稅。但出典人回贖時，原 繳之土地增值稅，應無息退還", "土地所有權人因重購土地退還土地增值稅者，其重購之土地，自完成移轉登記之日起，5 年內 再行移轉時，應追繳原退還稅款", "地價稅以每年9月22日為納稅義務基準日，於11月1日起1個月內一次徵收當年地價稅", "土地增值稅納稅義務人於收到土地增值稅繳納通知書後，應於30日內向公庫繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00154', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依現行土地稅法及相關法令規定，下列有關地價稅課徵敘述，何者正確？', '["地價稅採累進稅率，基本稅率為千分之二", "土地所有權人自用住宅優惠稅率，採全國土地之面積合併計算，非僅單一縣市土地面積合計", "都市計畫公共設施保留地無論作任何使用且與使用中之土地隔離者按千分之二課徵地價稅", "土地所有權人與其配偶及已成年之受扶養親屬，適用自用住宅用地稅率繳納地價稅者，以一處 為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "bff5c5a51904", "answer_pdf_sha1": "1650b6657902", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
